#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor rms_norm_impl_npu(const at::Tensor& self, double eps = 1e-5) {
    at::Tensor result = at::empty_like(self);
    EXEC_NPU_CMD(aclnnRmsNormCustom, self, eps, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("rms_norm_custom", &rms_norm_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("rms_norm_custom", &rms_norm_impl_npu,
          "RMS Normalization (RmsNormCustom on NPU)",
          py::arg("x"), py::arg("eps") = 1e-5);
}
